var plusOne = function(digits) {
    const d = digits.slice();
    for (let i = d.length - 1; i >= 0; i--) {
        if (d[i] < 9) {
            d[i] += 1;
            return d;
        }
        d[i] = 0;
    }
    return [1].concat(d);
};
